class FoodRatings:

    def __init__(self, foods: List[str], cuisines: List[str], ratings: List[int]):
        self.foods = {food: (rating, cuisine) for food, cuisine, rating in zip(foods, cuisines, ratings)}
        self.foods_by_cuisine = defaultdict(lambda: [])

    def changeRating(self, food: str, newRating: int) -> None:
        del self.foods[food]
        self.foods[food] = (newRating, self.foods[food][1])

    def highestRated(self, cuisine: str) -> str:
        return min((food for food, (rating, c) in self.foods.items() if c == cuisine and rating == max(r for r, c in self.foods.values() if c == cuisine)), key=lambda x: x)
